struct WaveRenderer: TextRenderer {
    var time: Double
    func draw(layout: Text.Layout, in ctx: inout GraphicsContext) {
        for line in layout {
            for (i, run) in line.enumerated() {
                var c = ctx
                c.translateBy(x: 0, y: sin(time + Double(i)) * 4)
                c.draw(run)
            }
        }
    }
}
